  ('elementary-7fec267e-moex-00326', 'elementary-7fec267e', 'elementary-7fec267e-moex-113-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '下列關於夫妻財產制之敘述，何者錯誤？', '["夫妻於結婚時未約定夫妻財產制者，適用法定財產制", "約定夫妻財產制者，僅應作成書面，即發生效力", "夫妻採共同財產制者，其各自之財產，無論是否專供個人使用之物或職業上必需之物，均合併為共同財 產，由雙方公同共有", "適用法定財產制之夫妻，仍得於婚姻關係存續中，約定改用分別財產制，或一方得以有法定事由為由， 請求法院宣告改用分別財產制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:59+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
